class MyClass {
private:
 int data;
 int* ptr;
public:
 // Parameter: const reference to same class
 MyClass(const MyClass& obj) {
 data = obj.data;
 // Shallow copy for primitive
 // Deep copy for pointers
 ptr = new int(*obj.ptr); // allocate new memory
 *ptr = *(obj.ptr); // copy value
 }
};

class String {
private:
 char* str;
 int length;
public:
 // Copy constructor with initializer list
 String(const String& obj) : str(nullptr) {
 length = obj.length;
 str = new char[length + 1];
 strcpy(str, obj.str);
 }

 ~String() {
 delete[] str;
 }
};

class Sample {
 int value;
public:
 Sample(int v) : value(v) {}

 // Copy constructor
 Sample(const Sample& obj) : value(obj.value) {
 cout << "Copy constructor called" << endl;
 }
};

// Scenario 1: Pass by value
void func(Sample s) { }

// Scenario 2: Return by value
Sample create() {
 Sample s(10);
 return s; // copy constructor called
}

int main() {
 Sample s1(5);
 Sample s2 = s1; // Scenario 3: initialization
 func(s1); // Scenario 1: pass by value
 Sample s3 = create(); // Scenario 2: return by value
}

class NonCopyable {
 int data;
public:
 NonCopyable(int d) : data(d) {}

 // Delete copy constructor
 NonCopyable(const NonCopyable&) = delete;

 // Delete copy assignment
 NonCopyable& operator=(const NonCopyable&) = delete;
};

int main() {
 NonCopyable a(10);
 NonCopyable b = a; // Error: use of deleted function
 a = b; // Error: use of deleted function
}

class Buffer {
private:
 char* data;
 int size;
public:
 Buffer(int s) : size(s) {
 data = new char[size];
 }

 // Destructor
 ~Buffer() {
 delete[] data;
 }

 // Copy Constructor (Deep Copy)
 Buffer(const Buffer& obj) : size(obj.size) {
 data = new char[size];
 memcpy(data, obj.data, size);
 }

 // Copy Assignment Operator
 Buffer& operator=(const Buffer& obj) {
 if (this != &obj) { // self-assignment check
 delete[] data;
 size = obj.size;
 data = new char[size];
 memcpy(data, obj.data, size);
 }
 return *this;
 }
};
